     2|// Called by external webhook when content changes in the database
     3|// POST /api/revalidate?secret=<key>&path=<path>
     4|
     5|import { NextRequest, NextResponse } from 'next/server'
     6|import { revalidatePath } from 'next/cache'
     7|
     8|const REVALIDATION_SECRET = process.env.REVALIDATION_SECRET || 'nexa-isr-secret-dev'
     9|
    10|export async function POST(request: NextRequest) {
    11|  const searchParams = request.nextUrl.searchParams
    12|  const secret = searchParams.get('secret')
    13|  const path = searchParams.get('path')
    14|
    15|  if (!secret || secret !== REVALIDATION_SECRET) {
    16|    return NextResponse.json({ error: 'Invalid secret' }, { status: 401 })
    17|  }
    18|
    19|  if (path) {
    20|    revalidatePath(path)
    21|    return NextResponse.json({ revalidated: true, path, now: Date.now() })
    22|  }
    23|
    24|  // No specific path — revalidate all known paths
    25|  const locales = ['nl', 'en', 'es', 'de']
    26|  const pages = ['', '/sobre', '/servicios', '/por-que-paraguay', '/faq', '/blog', '/contacto', '/proceso']
    27|
    28|  for (const locale of locales) {
    29|    for (const page of pages) {
    30|      revalidatePath(`/${locale}${page}`)
    31|    }
    32|  }
    33|
    34|  return NextResponse.json({ revalidated: true, paths: locales.length * pages.length, now: Date.now() })
    35|}
    36|
    37|export async function GET(request: NextRequest) {
    38|  const searchParams = request.nextUrl.searchParams
    39|  
    40|  // Support GET for simple webhooks
    41|  if (searchParams.get('secret')) {
    42|    return POST(request)
    43|  }
    44|
    45|  return NextResponse.json({ error: 'Use POST with ?secret=key' }, { status: 400 })
