{"content": "     1|import { supabaseAdmin, TENANT_SLUG, STORAGE_BASE } from './supabase'
     2|import { readFileSync, existsSync } from 'fs'
     3|import { join } from 'path'
     4|
     5|const REPO = process.cwd()
     6|
     7|// ── In-memory LRU cache ──
     8|interface CacheEntry { data: any; timestamp: number }
     9|const cache = new Map<string, CacheEntry>()
    10|const TTL = 30_000 // 30s between renders
    11|
    12|function getCached(key: string): any | null {
    13|  const entry = cache.get(key)
    14|  if (entry && (Date.now() - entry.timestamp) < TTL) return entry.data
    15|  return null
    16|}
    17|
    18|function setCache(key: string, data: any) {
    19|  cache.set(key, { data, timestamp: Date.now() })
    20|}
    21|
    22|// Keep map bounded at 20 entries
    23|function pruneCache() {
    24|  if (cache.size > 20) {
    25|    const entries = [...cache.entries()].sort((a, b) => a[1].timestamp - b[1].timestamp)
    26|    const toDelete = entries.slice(0, cache.size - 20)
    27|    for (const [key] of toDelete) cache.delete(key)
    28|  }
    29|}
    30|
    31|// ── Tenant config loader (Supabase → file fallback) ──
    32|let _tenantConfig: any = null
    33|
    34|async function loadTenantConfig(): Promise<any> {
    35|  if (_tenantConfig) return _tenantConfig
    36|
    37|  // Try Supabase first
    38|  try {
    39|    const { data, error } = await supabaseAdmin
    40|      .from('tenant_config')
    41|      .select('*')
    42|      .eq('tenant_slug', TENANT_SLUG)
    43|      .single()
    44|
    45|    if (data && !error) {
    46|      _tenantConfig = data
    47|      return data
    48|    }
    49|  } catch (e) {
    50|    // Supabase unavailable — fall through to file
    51|  }
    52|
    53|  // Fallback: read from files
    54|  try {
    55|    const site = JSON.parse(readFileSync(join(REPO, 'site.json'), 'utf-8'))
    56|    const content: Record<string, any> = {}
    57|    for (const locale of site.locales || ['es', 'en', 'nl', 'de']) {
    58|      try {
    59|        content[locale] = JSON.parse(readFileSync(join(REPO, 'content', `${locale}.json`), 'utf-8'))
    60|      } catch {}
    61|    }
    62|    const images = JSON.parse(readFileSync(join(REPO, 'images.json'), 'utf-8'))
    63|    const testimonials = JSON.parse(readFileSync(join(REPO, 'testimonials.json'), 'utf-8'))
    64|    const pages: Record<string, any> = {}
    65|    const pagesDir = join(REPO, 'nexa-pages')
    66|    if (existsSync(pagesDir)) {
    67|      const fs = require('fs')
    68|      const path = require('path')
    69|      for (const f of fs.readdirSync(pagesDir)) {
    70|        if (f.endsWith('.json')) {
    71|          const name = f.replace('.json', '')
    72|          pages[name] = JSON.parse(readFileSync(join(pagesDir, f), 'utf-8'))
    73|        }
    74|      }
    75|    }
    76|    const blogPosts: Record<string, any> = {}
    77|    const blogDir = join(REPO, 'content', 'blog')
    78|    if (existsSync(blogDir)) {
    79|      const fs = require('fs')
    80|      for (const f of fs.readdirSync(blogDir)) {
    81|        if (f.startsWith('posts') && f.endsWith('.json')) {
    82|          blogPosts[f] = JSON.parse(readFileSync(join(blogDir, f), 'utf-8'))
    83|        }
    84|      }
    85|    }
    86|
    87|    _tenantConfig = {
    88|      tenant_slug: TENANT_SLUG,
    89|      site,
    90|      content,
    91|      images,
    92|      testimonials,
    93|      pages,
    94|      blog_posts: blogPosts,
    95|    }
    96|    return _tenantConfig
    97|  } catch {
    98|    return null
    99|  }
