   104|export async function loadJSONAsync(dir: string, file: string): Promise<any> {
   105|  const key = `json:${dir}/${file}`
   106|  const cached = getCached(key)
   107|  if (cached) return cached
   108|
   109|  try {
   110|    const data = JSON.parse(readFileSync(join(dir, file), 'utf-8'))
   111|    setCache(key, data)
   112|    pruneCache()
   113|    return data
   114|  } catch { return null }
