   116|
   117|// Keep synchronous version for compatibility
   118|export function loadJSON(dir: string, file: string): any {
   119|  const key = `json:${dir}/${file}`
   120|  const cached = getCached(key)
   121|  if (cached) return cached
   122|  try {
   123|    const data = JSON.parse(readFileSync(join(dir, file), 'utf-8'))
   124|    setCache(key, data)
